#include <bits/stdc++.h>
using namespace std;
//#define ll long long
const int N=133338;
int n,m,a[N],block,ans[N],qcnt,bcnt,vis[1000005],anss;
int fun(int x)
{
	return (x-1)/block+1;
}
struct node
{
	int l,r,tim,id;
	bool operator<(const node other) const
	{
		if(fun(l)!=fun(other.l)) return fun(l)<fun(other.l);
		if(fun(r)!=fun(other.r)) return fun(r)<fun(other.r);
		return tim<other.tim;
	}
} q[N];
struct Node
{
	int pos,val;
} b[N];
void add(int val)
{
	if(++vis[val]==1) anss++;
}
void del(int val)
{
	if(--vis[val]==0) anss--;
}
void change_tim(int x,int y)
{
	if(b[x].pos>=q[y].l&&b[x].pos<=q[y].r)
	{
		if(--vis[a[b[x].pos]]==0) anss--;
		if(++vis[b[x].val]==1) anss++;
	}
	swap(b[x].val,a[b[x].pos]);
}
int main()
{
	cin>>n>>m;
	block=pow(n,0.666);
//	cout<<"block : "<<block<<"\n";
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	while(m--)
	{
		string s;
		cin>>s;
		if(s=="Q")
		{
			qcnt++;
			cin>>q[qcnt].l>>q[qcnt].r;
//			cout<<q[qcnt].l<<"  "<<q[qcnt].r<<"\n";
			q[qcnt].id=qcnt;
			q[qcnt].tim=bcnt;
		}
		else
		{
			bcnt++;
			cin>>b[bcnt].pos>>b[bcnt].val;
		}
	}
	sort(q+1,q+1+qcnt);
	int l=1,r=0,tim=0;
	for(int i=1;i<=qcnt;i++)
	{
		int ll=q[i].l,rr=q[i].r,tt=q[i].tim;
		while(l<ll)
		{
			del(a[l++]);
		}
		while(l>ll)
		{
			add(a[--l]);
		}
		while(r<rr)
		{
			add(a[++r]);
		}
		while(r>rr)
		{
			del(a[r--]);
		}
		while(tim<tt)
		{
			change_tim(++tim,i);
		}
		while(tim>tt)
		{
			change_tim(tim--,i);
		}
//		cout<<q[i].id<<"  ll: "<<ll<<"  rr: "<<rr<<"  anss : "<<anss<<"\n";
//		cout<<vis[1]<<"  "<<vis[2]<<"  "<<vis[3]<<"  "<<vis[4]<<"  "<<vis[5]<<"\n";
		ans[q[i].id]=anss;
	}
	for(int i=1;i<=qcnt;i++)
	{
		cout<<ans[i]<<"\n";
	}
	return 0;
}
